// var item = require('../items.json')
export default {
  name: 'new',
  data () {
    return {
      saleShow: false,
      topShow: false,
      bottomShow: false,
      onePieceShow: false,
      homeWearShow: false,
      accessoryShow: false,
      items: []
    }
  },
  async mounted () {
    const res = await fetch('../items.json')
    const data = await res.json()
    // const data = require('../items.json')
    this.items = data
    console.log(data)
  }
}
